// Pinia + Vue: store para reloj
// stores/clock.js
import { defineStore } from 'pinia';

export const useClockStore = defineStore('clock', {
  state: () => ({ time: '' , t: null }),
  actions: {
    start(){
      this.time = new Date().toLocaleTimeString();
      this.t = setInterval(() => { this.time = new Date().toLocaleTimeString(); }, 1000);
    },
    stop(){
      if (this.t) clearInterval(this.t);
      this.t = null;
    }
  }
});

